public function getIndustryCategories($category_id) {
	$this->createIndustryCategoryTable();

	$query = $this->db->query("SELECT cic.related_category_id AS category_id, cic.sort_order, cd.name, (SELECT GROUP_CONCAT(cd1.name ORDER BY cp.level SEPARATOR '&nbsp;&nbsp;&gt;&nbsp;&nbsp;') FROM " . DB_PREFIX . "category_path cp LEFT JOIN " . DB_PREFIX . "category_description cd1 ON (cp.path_id = cd1.category_id) WHERE cp.category_id = cic.related_category_id AND cd1.language_id = '" . (int)$this->config->get('config_language_id') . "' GROUP BY cp.category_id) AS path FROM " . DB_PREFIX . "category_industry_category cic LEFT JOIN " . DB_PREFIX . "category_description cd ON (cic.related_category_id = cd.category_id) WHERE cic.category_id = '" . (int)$category_id . "' AND cd.language_id = '" . (int)$this->config->get('config_language_id') . "' ORDER BY cic.sort_order ASC, LCASE(cd.name) ASC");

	return $query->rows;
}

public function setIndustryCategories($category_id, $industry_categories) {
	$this->createIndustryCategoryTable();

	$this->db->query("DELETE FROM " . DB_PREFIX . "category_industry_category WHERE category_id = '" . (int)$category_id . "'");

	if (!empty($industry_categories) && is_array($industry_categories)) {
		foreach ($industry_categories as $related_category_id => $category_data) {
			$related_category_id = (int)$related_category_id;

			if ($related_category_id <= 0 || $related_category_id === (int)$category_id) {
				continue;
			}

			$sort_order = isset($category_data['sort_order']) ? (int)$category_data['sort_order'] : 0;

			$this->db->query("REPLACE INTO " . DB_PREFIX . "category_industry_category SET category_id = '" . (int)$category_id . "', related_category_id = '" . (int)$related_category_id . "', sort_order = '" . $sort_order . "'");
		}
	}
}

private function createIndustryCategoryTable() {
	$this->db->query("CREATE TABLE IF NOT EXISTS `" . DB_PREFIX . "category_industry_category` (`category_id` int(11) NOT NULL, `related_category_id` int(11) NOT NULL, `sort_order` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`category_id`, `related_category_id`), KEY `related_category_id` (`related_category_id`), KEY `sort_order` (`sort_order`)) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci");
}

if (isset($this->request->post['industry_category'])) {
	$industry_categories = $this->request->post['industry_category'];
} elseif (isset($category_info)) {
	$industry_categories = $this->model_catalog_category->getIndustryCategories($this->request->get['category_id']);
} else {
	$industry_categories = array();
}

$data['industry_categories'] = array();

foreach ($industry_categories as $key => $industry_category) {
	$industry_category_id = isset($industry_category['category_id']) ? (int)$industry_category['category_id'] : (int)$key;
	$industry_category_info = $this->model_catalog_category->getCategory($industry_category_id);

	if ($industry_category_info) {
		$data['industry_categories'][] = array(
			'category_id' => $industry_category_id,
			'name'        => strip_tags(html_entity_decode(!empty($industry_category['path']) ? $industry_category['path'] : (($industry_category_info['path'] ? $industry_category_info['path'] . '&nbsp;&nbsp;&gt;&nbsp;&nbsp;' : '') . $industry_category_info['name']), ENT_QUOTES, 'UTF-8')),
			'sort_order'  => isset($industry_category['sort_order']) ? (int)$industry_category['sort_order'] : 0
		);
	}
}

public function getIndustryCategories($category_id) {
	$this->createIndustryCategoryTable();

	$query = $this->db->query("SELECT c.category_id, c.image, cd.name, (SELECT GROUP_CONCAT(cp.path_id ORDER BY cp.level SEPARATOR '_') FROM " . DB_PREFIX . "category_path cp WHERE cp.category_id = c.category_id GROUP BY cp.category_id) AS path FROM " . DB_PREFIX . "category_industry_category cic LEFT JOIN " . DB_PREFIX . "category c ON (cic.related_category_id = c.category_id) LEFT JOIN " . DB_PREFIX . "category_description cd ON (c.category_id = cd.category_id) LEFT JOIN " . DB_PREFIX . "category_to_store c2s ON (c.category_id = c2s.category_id) WHERE cic.category_id = '" . (int)$category_id . "' AND cd.language_id = '" . (int)$this->config->get('config_language_id') . "' AND c2s.store_id = '" . (int)$this->config->get('config_store_id') . "' AND c.status = '1' ORDER BY cic.sort_order ASC, c.sort_order ASC, LCASE(cd.name) ASC");

	return $query->rows;
}

private function createIndustryCategoryTable() {
	$this->db->query("CREATE TABLE IF NOT EXISTS `" . DB_PREFIX . "category_industry_category` (`category_id` int(11) NOT NULL, `related_category_id` int(11) NOT NULL, `sort_order` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`category_id`, `related_category_id`), KEY `related_category_id` (`related_category_id`), KEY `sort_order` (`sort_order`)) ENGINE=MyISAM DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci");
}
